#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n,m; scanf("%d %d",&n,&m);
        int a[n][m];
        for(int i=0;i<n;i++) for(int j=0;j<m;j++) scanf("%d",&a[i][j]);
        for(int i=0;i<n;i++){
            for(int j=0;j<m;j++){
                int b; scanf("%d",&b);
                printf("%d", a[i][j]+b);
                if(j+1<m) printf(" ");
            }
            printf("\n");
        }
    }
    return 0;
}

