import sys
def main():
    data=list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it=iter(data)
    T=next(it)
    out=[]
    for _ in range(T):
        n=next(it); m=next(it)
        a=[[next(it) for _ in range(m)] for __ in range(n)]
        for i in range(n):
            row=[]
            for j in range(m):
                b=next(it)
                row.append(str(a[i][j]+b))
            out.append(' '.join(row))
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    main()

