const fs=require('fs');
const data=fs.readFileSync(0,'utf-8').trim().split(/\s+/).map(Number);
let idx=0;
const T=data[idx++];
let out=[];
for(let t=0;t<T;t++){
  const n=data[idx++];
  const m=data[idx++];
  const a=Array.from({length:n},()=>data.slice(idx, idx+=m));
  const b=Array.from({length:n},()=>data.slice(idx, idx+=m));
  for(let i=0;i<n;i++){
    const row=[];
    for(let j=0;j<m;j++) row.push(a[i][j]+b[i][j]);
    out.push(row.join(' '));
  }
}
